+import { describe, it, expect, beforeEach } from 'vitest';
+import {
+  SmsNotificationAdapter,
+  isValidPhoneNumber,
+  resolveRecipient,
+  formatSmsBody,
+} from '../../src/adapters/sms.adapter.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
+  return {
+    id: 'notif-0001',
+    type: 'order_confirmation',
+    channel: 'sms',
+    recipient: '+15551234567',
+    subject: 'Order Confirmation: order-1',
+    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
+    priority: 'normal',
+    createdAt: new Date('2026-01-15T12:00:00Z'),
+    metadata: { orderId: 'order-1', userId: 'user-1' },
+    ...overrides,
+  };
+}
+
+describe('isValidPhoneNumber', () => {
+  it('should accept valid E.164 phone numbers', () => {
+    expect(isValidPhoneNumber('+15551234567')).toBe(true);
+    expect(isValidPhoneNumber('+447911123456')).toBe(true);
+    expect(isValidPhoneNumber('15551234567')).toBe(true);
+    expect(isValidPhoneNumber('+1234567')).toBe(true);
+  });
+
+  it('should reject invalid phone numbers', () => {
+    expect(isValidPhoneNumber('')).toBe(false);
+    expect(isValidPhoneNumber('not-a-number')).toBe(false);
+    expect(isValidPhoneNumber('abc123')).toBe(false);
+    expect(isValidPhoneNumber('+0123456')).toBe(false);
+    expect(isValidPhoneNumber('123')).toBe(false);
+    expect(isValidPhoneNumber('+1234567890123456')).toBe(false);
+  });
+});
+
+describe('resolveRecipient', () => {
+  it('should return recipient directly if it is a valid phone number', () => {
+    expect(resolveRecipient('+15551234567')).toBe('+15551234567');
+  });
+
+  it('should fall back to metadata phoneNumber', () => {
+    expect(resolveRecipient('user-1', { phoneNumber: '+15559876543' })).toBe('+15559876543');
+  });
+
+  it('should return null if recipient is not a phone number and no metadata', () => {
+    expect(resolveRecipient('user-1')).toBeNull();
+  });
+
+  it('should return null if metadata phoneNumber is invalid', () => {
+    expect(resolveRecipient('user-1', { phoneNumber: 'bad' })).toBeNull();
+  });
+});
+
+describe('formatSmsBody', () => {
+  it('should format a short message without truncation', () => {
+    const payload = makePayload({ subject: 'Hi', body: 'Hello' });
+    const result = formatSmsBody(payload, 160);
+
+    expect(result.body).toBe('Hi: Hello');
+    expect(result.truncated).toBe(false);
