+        recipient: 'user-1',
+        metadata: { orderId: 'order-1', userId: 'user-1', phoneNumber: '+15559876543' },
+      });
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      const sent = adapter.getSentMessages();
+      expect(sent[0]!.message.to).toBe('+15559876543');
+    });
+
+    it('should fail for invalid recipient with no phone metadata', async () => {
+      const payload = makePayload({ recipient: 'user-1', metadata: { orderId: 'order-1' } });
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid recipient');
+      expect(adapter.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should truncate long messages to configured maxLength', async () => {
+      const shortAdapter = new SmsNotificationAdapter({
+        provider: 'test',
+        fromNumber: '+15550000000',
+        maxLength: 50,
+      });
+
+      const payload = makePayload();
+      await shortAdapter.send(payload);
+
+      const sent = shortAdapter.getSentMessages();
+      expect(sent[0]!.message.body.length).toBe(50);
+      expect(sent[0]!.message.truncated).toBe(true);
+    });
+
+    it('should handle high priority notifications', async () => {
+      const payload = makePayload({
+        priority: 'high',
+        subject: 'Order Cancelled',
+        body: 'Your order has been cancelled.',
+      });
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      const sent = adapter.getSentMessages();
+      expect(sent[0]!.message.body).toContain('[HIGH]');
+    });
+  });
+
+  describe('getSentMessages / clearSentMessages', () => {
+    it('should return a copy of sent messages', async () => {
+      await adapter.send(makePayload());
+      const messages = adapter.getSentMessages();
+      messages.pop();
+      expect(adapter.getSentMessages()).toHaveLength(1);
+    });
+
+    it('should clear all sent messages', async () => {
+      await adapter.send(makePayload());
+      adapter.clearSentMessages();
+      expect(adapter.getSentMessages()).toHaveLength(0);
+    });
+  });
+});
+
+describe('SmsNotificationAdapter integration with NotificationService', () => {
+  it('should work end-to-end with EventBus and NotificationService', async () => {
+    const { EventBus } = await import('../../src/events/event-bus.js');
+    const { NotificationService, resetNotificationIdCounter } = await import(
+      '../../src/services/notification.service.js'
+    );
+
+    const eventBus = new EventBus();
+    const service = new NotificationService(eventBus);
+    const adapter = new SmsNotificationAdapter({
+      provider: 'test',
+      fromNumber: '+15550000000',
+    });
+    resetNotificationIdCounter();
+
+    service.registerAdapter(adapter);
+
+    // Send an SMS notification directly through the service
+    await service.send({
+      type: 'order_confirmation',
+      channel: 'sms',
+      recipient: '+15551234567',
+      subject: 'Order Confirmation: order-42',
+      body: 'Your order has been placed. Items: Widget x3. Total: $45.00',
+      priority: 'normal',
+      metadata: { orderId: 'order-42', userId: 'user-1' },
+    });
+
+    const notifications = service.getNotifications();
+    expect(notifications).toHaveLength(1);
+    expect(notifications[0]!.status).toBe('sent');
+    expect(notifications[0]!.channel).toBe('sms');
+
+    const sent = adapter.getSentMessages();
+    expect(sent).toHaveLength(1);
+    expect(sent[0]!.message.to).toBe('+15551234567');
+    expect(sent[0]!.message.body).toContain('order-42');
+  });
+});

