/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Implements phone number validation, message formatting for SMS character
 * limits, and structured delivery. In non-production environments, messages
 * are captured in memory for testing and inspection.
 *
 * NOTE ON USER PREFERENCES:
 * The current UserPreferences model (src/models/user-preferences.ts) was designed
 * with an email-only assumption. It has an `email: EmailPreferences` field but no
 * equivalent `sms: SmsPreferences` field. The PreferencesService only exposes
 * `shouldSendEmail()` — there is no `shouldSendSms()` method.
 *
 * Before SMS notifications can be gated by user preferences, the following
 * changes are needed:
 *   1. Add an SmsPreferences interface to src/models/user-preferences.ts
 *      (enabled, subscribedCategories — frequency is less relevant for SMS).
 *   2. Add an `sms` field to the UserPreferences interface.
 *   3. Update getDefaultEmailPreferences() → getDefaultPreferences() or add
 *      a getDefaultSmsPreferences() helper.
 *   4. Add `shouldSendSms(userId, type)` to PreferencesService.
 *   5. Update PreferencesRepository serialization to handle the new field.
 *   6. Update NotificationService.isAllowedByPreferences() to call
 *      shouldSendSms() when channel === 'sms'.
 *
 * Until then, SMS notifications bypass preference checks (isAllowedByPreferences
 * returns true for unknown channels).
 */

import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import type { NotificationAdapter } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

export interface SmsConfig {
  /** SMS provider identifier (e.g. 'twilio', 'sns'). */
  provider: string;
  /** Sender phone number or short code (e.g. '+15551234567'). */
  fromNumber: string;
  /** Maximum message length before truncation (default: 160). */
  maxLength?: number;
}

export const defaultSmsConfig: SmsConfig = {
  provider: 'default',
  fromNumber: '+15550000000',
  maxLength: 160,
};

/** A sent SMS record for inspection/testing. */
export interface SentSms {
  payload: NotificationPayload;
  message: FormattedSms;
  sentAt: Date;
}

/** Formatted SMS ready for transport. */
export interface FormattedSms {
  from: string;
  to: string;
  body: string;
  truncated: boolean;
}

/**
 * Validate a phone number format.
 * Accepts E.164 format: optional +, followed by digits only, 7-15 digits total.
 */
export function isValidPhoneNumber(phone: string): boolean {
  if (!phone || typeof phone !== 'string') return false;
  return /^\+?[1-9]\d{6,14}$/.test(phone);
}

/**
 * Resolve a recipient identifier to a deliverable phone number.
 * If the recipient is already a valid phone number, use it directly.
 * Otherwise, check metadata for a phoneNumber field.
 */
export function resolveRecipient(
  recipient: string,
  metadata?: Record<string, unknown>,
): string | null {
  if (isValidPhoneNumber(recipient)) {
    return recipient;
  }

  if (metadata?.phoneNumber && typeof metadata.phoneNumber === 'string' && isValidPhoneNumber(metadata.phoneNumber)) {
    return metadata.phoneNumber;
  }

  return null;
}

/**
 * Format a notification payload into an SMS message body.
 * Truncates to maxLength with an ellipsis if the message is too long.
 */
export function formatSmsBody(payload: NotificationPayload, maxLength: number): { body: string; truncated: boolean } {
  const prefix = payload.priority === 'high' || payload.priority === 'urgent'
    ? `[${payload.priority.toUpperCase()}] `
    : '';

  const full = `${prefix}${payload.subject}: ${payload.body}`;

  if (full.length <= maxLength) {
    return { body: full, truncated: false };
  }

  return { body: full.substring(0, maxLength - 3) + '...', truncated: true };
}

export class SmsNotificationAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private sentMessages: SentSms[] = [];

  constructor(private config: SmsConfig = defaultSmsConfig) {}

  /**
   * Send an SMS notification.
   * Validates recipient phone number, formats message, and delivers.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const toNumber = resolveRecipient(payload.recipient, payload.metadata);

      if (!toNumber) {
        this.logger.error(
          `Cannot resolve recipient "${payload.recipient}" to a valid phone number`,
        );
        return {
          success: false,
          notificationId: payload.id,
          channel: 'sms',
          deliveredAt: new Date(),
          error: `Invalid recipient: ${payload.recipient}`,
        };
      }

      const maxLength = this.config.maxLength ?? 160;
      const { body, truncated } = formatSmsBody(payload, maxLength);

      if (truncated) {
        this.logger.info(`SMS message truncated to ${maxLength} characters for ${payload.id}`);
      }

      const message: FormattedSms = {
        from: this.config.fromNumber,
        to: toNumber,
        body,
        truncated,
      };

      // In-memory transport for now — swap for real SMS provider in production
      this.logger.info(
        `Sending SMS to ${toNumber}: "${payload.subject}" (from: ${this.config.fromNumber})`,
      );

      this.sentMessages.push({ payload, message, sentAt: new Date() });

      return {
        success: true,
        notificationId: payload.id,
        channel: 'sms',
        deliveredAt: new Date(),
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown SMS error';
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${message}`);

      return {
        success: false,
        notificationId: payload.id,
        channel: 'sms',
        deliveredAt: new Date(),
        error: message,
      };
    }
  }

  /** Get all SMS messages sent through this adapter (useful for testing). */
  getSentMessages(): SentSms[] {
    return [...this.sentMessages];
  }

  /** Clear sent messages (useful for testing). */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

